const body = $input.first().json.body;

const platform   = body.platform  || 'nie podano';
const orders     = body.orders    || 'nie podano';
const industry   = body.industry  || 'nie podano';
const tools      = body.tools     || 'nie podano';
const extra      = body.extra     || 'brak';
const clientName = body.name      || 'Klient';
const clientEmail= body.email     || '';
const clientPhone= body.phone     || 'nie podano';
const shopUrl    = body.shopUrl   || 'nie podano';
const budget     = body.budget    || 'nie podano';

let processes = [];
if (Array.isArray(body.processes)) {
  processes = body.processes;
} else if (typeof body.processes === 'string') {
  processes = body.processes.split(',').map(p => p.trim()).filter(Boolean);
}
const processList = processes.join(', ');

// Unikalny ID oferty
const offerId = 'AF-' + Date.now().toString(36).toUpperCase();
const offerDate = new Date().toLocaleDateString('pl-PL', { day: 'numeric', month: 'long', year: 'numeric' });

const prompt = `Jesteś ekspertem automatyzacji e-commerce. Napisz profesjonalną ofertę handlową PO POLSKU.

DANE KLIENTA:
- Imię/firma: ${clientName}
- Platforma: ${platform}
- Sklep: ${shopUrl}
- Zamówienia/mies.: ${orders}
- Branża: ${industry}
- Używane narzędzia: ${tools}
- Procesy do automatyzacji: ${processList}
- Budżet: ${budget}
- Dodatkowe info: ${extra}

Struktura oferty:
1. Personalizowane powitanie używające imienia/nazwy firmy
2. Analiza sytuacji (2-3 zdania pokazujące zrozumienie ich biznesu)
3. Proponowane rozwiązania (3-5 konkretnych automatyzacji z n8n/Make.com)
4. Harmonogram wdrożenia (tabela: etap, zakres, czas)
5. Inwestycja (podaj konkretną cenę lub zakres, np. 3500-4500 zł)
6. Co wchodzi w pakiet (lista 5-7 punktów)
7. Gwarancja i wsparcie po wdrożeniu
8. Proponowany kolejny krok ("Odpiszę w ciągu 24h aby umówić 30-minutową konsultację")

Na końcu w osobnej linii:
CENA: [konkretna kwota lub zakres np. 4000-5500 zł]
PACKAGE: [Starter|Growth|Retainer]

Ton: profesjonalny, partnerski, konkretny. Max 500 słów.`;

return [{
  json: {
    prompt,
    offerId,
    offerDate,
    clientName,
    clientEmail,
    clientPhone,
    platform,
    orders,
    industry,
    processList,
    budget,
    shopUrl
  }
}];

const claudeResp = $input.first().json;
const prev = $('3. Przygotuj dane i prompt').first().json;

let fullText = '';
if (claudeResp.content && Array.isArray(claudeResp.content)) {
  fullText = claudeResp.content.filter(b => b.type === 'text').map(b => b.text).join('');
}

const priceMatch   = fullText.match(/CENA:\s*([^\n]+)/i);
const packageMatch = fullText.match(/PACKAGE:\s*([^\n]+)/i);
const price   = priceMatch   ? priceMatch[1].trim()   : 'Do ustalenia';
const pkg     = packageMatch ? packageMatch[1].trim() : 'Growth';
const offerText = fullText.replace(/CENA:[^\n]*/i, '').replace(/PACKAGE:[^\n]*/i, '').trim();

// Zbuduj URL zatwierdzenia i odrzucenia (przez kolejny webhook)
const baseUrl = 'https://TWOJA-DOMENA.n8n.cloud/webhook';
const approveUrl = `${baseUrl}/zatwierdz-oferte?id=${prev.offerId}&action=approve&email=${encodeURIComponent(prev.clientEmail)}&name=${encodeURIComponent(prev.clientName)}&price=${encodeURIComponent(price)}&pkg=${encodeURIComponent(pkg)}`;
const rejectUrl  = `${baseUrl}/zatwierdz-oferte?id=${prev.offerId}&action=reject&email=${encodeURIComponent(prev.clientEmail)}&name=${encodeURIComponent(prev.clientName)}`;

return [{
  json: {
    ...prev,
    offerText,
    price,
    pkg,
    approveUrl,
    rejectUrl
  }
}];

const q = $input.first().json.query;

const offerId     = q.id    || 'AF-XXX';
const clientEmail = decodeURIComponent(q.email || '');
const clientName  = decodeURIComponent(q.name  || 'Kliencie');
const price       = decodeURIComponent(q.price || 'Do ustalenia');
const pkg         = decodeURIComponent(q.pkg   || 'Growth');
const today       = new Date().toLocaleDateString('pl-PL', { day: 'numeric', month: 'long', year: 'numeric' });

// Termin ważności oferty (14 dni)
const validUntil = new Date();
validUntil.setDate(validUntil.getDate() + 14);
const validUntilStr = validUntil.toLocaleDateString('pl-PL', { day: 'numeric', month: 'long', year: 'numeric' });

// Mapowanie pakietu na szczegóły
const packages = {
  'Starter': { workflows: '1 workflow', integrations: '2 systemy', support: '30 dni', price: price },
  'Growth':  { workflows: 'do 4 workflow', integrations: 'do 5 systemów', support: '60 dni', price: price },
  'Retainer':{ workflows: 'do 8h/mies.', integrations: 'bez limitu', support: 'bezterminowo', price: price }
};
const pkgDetails = packages[pkg] || packages['Growth'];

return [{
  json: {
    offerId,
    clientEmail,
    clientName,
    price,
    pkg,
    pkgDetails,
    today,
    validUntilStr
  }
}];
